+            let mut future = Next::new(&mut stream);
+            match Pin::new(&mut future).poll(&mut cx) {
+                Poll::Ready(Some(2)) => {}
+                _ => panic!("expected Ready(Some(2))"),
+            }
+        }
+
+        {
+            let mut future = Next::new(&mut stream);
+            match Pin::new(&mut future).poll(&mut cx) {
+                Poll::Ready(Some(3)) => {}
+                _ => panic!("expected Ready(Some(3))"),
